import{_ as t,c as a,o,a1 as i}from"./chunks/framework.DILC4Csi.js";const g=JSON.parse('{"title":"Antigravity Auth: Access Claude & Gemini 3 | opencode-antigravity-auth","description":"Learn the core value and risks of the Antigravity Auth plugin. Access Claude and Gemini 3 models via Google OAuth with multi-account load balancing.","frontmatter":{"title":"Antigravity Auth: Access Claude & Gemini 3 | opencode-antigravity-auth","sidebarTitle":"Overview","subtitle":"Understand the Core Value of Antigravity Auth Plugin","description":"Learn the core value and risks of the Antigravity Auth plugin. Access Claude and Gemini 3 models via Google OAuth with multi-account load balancing.","tags":["Getting Started","Plugin Overview","OpenCode","Antigravity"],"order":1},"headers":[],"relativePath":"NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md","filePath":"NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"}'),n={name:"NoeFabris/opencode-antigravity-auth/start/what-is-antigravity-auth/index.md"};function l(r,e,s,u,c,d){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="understand-the-core-value-of-antigravity-auth-plugin" tabindex="-1">Understand the Core Value of Antigravity Auth Plugin <a class="header-anchor" href="#understand-the-core-value-of-antigravity-auth-plugin" aria-label="Permalink to &quot;Understand the Core Value of Antigravity Auth Plugin&quot;">​</a></h1><p><strong>Antigravity Auth</strong> is an OpenCode plugin that accesses the Antigravity API through Google OAuth authentication. It lets you use your familiar Google account to call advanced models like Claude Opus 4.5, Sonnet 4.5, and Gemini 3 Pro/Flash without managing API keys. The plugin also provides features like multi-account load balancing, dual quota pools, and automatic session recovery, making it ideal for users who need advanced models and automated management.</p><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Determine if this plugin fits your use case</li><li>Understand which AI models and core features are supported</li><li>Clarify the risks and precautions of using this plugin</li><li>Decide whether to proceed with installation and configuration</li></ul><h2 id="your-current-challenge" tabindex="-1">Your Current Challenge <a class="header-anchor" href="#your-current-challenge" aria-label="Permalink to &quot;Your Current Challenge&quot;">​</a></h2><p>You want to use the most advanced AI models (such as Claude Opus 4.5, Gemini 3 Pro), but official access is restricted. You&#39;re looking for a reliable way to access these models while hoping to:</p><ul><li>Avoid manually managing multiple API keys</li><li>Automatically switch accounts when encountering rate limits</li><li>Automatically recover after interruptions without losing context</li></ul><h2 id="core-concept" tabindex="-1">Core Concept <a class="header-anchor" href="#core-concept" aria-label="Permalink to &quot;Core Concept&quot;">​</a></h2><p><strong>Antigravity Auth</strong> is an OpenCode plugin that accesses the Google Antigravity API through <strong>Google OAuth authentication</strong>, allowing you to call advanced AI models using your familiar Google account.</p><p>It doesn&#39;t proxy all requests but <strong>intercepts and transforms</strong> your model call requests, forwards them to the Antigravity API, then converts the response back to a format that OpenCode can recognize.</p><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><h3 id="supported-models" tabindex="-1">Supported Models <a class="header-anchor" href="#supported-models" aria-label="Permalink to &quot;Supported Models&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Model Series</th><th>Available Models</th><th>Features</th></tr></thead><tbody><tr><td><strong>Claude</strong></td><td>Opus 4.5, Sonnet 4.5</td><td>Supports extended thinking mode</td></tr><tr><td><strong>Gemini 3</strong></td><td>Pro, Flash</td><td>Google Search integration, extended thinking</td></tr></tbody></table><div class="info custom-block"><p class="custom-block-title">Thinking Mode</p><p>Thinking models perform &quot;deep thinking&quot; before generating responses, showing their reasoning process. You can configure thinking budget to balance quality and response speed.</p></div><h3 id="multi-account-load-balancing" tabindex="-1">Multi-Account Load Balancing <a class="header-anchor" href="#multi-account-load-balancing" aria-label="Permalink to &quot;Multi-Account Load Balancing&quot;">​</a></h3><ul><li><strong>Supports up to 10 Google accounts</strong></li><li>Automatically switches to the next account when encountering rate limits (429 errors)</li><li>Three account selection strategies: sticky, round-robin, hybrid (smart mixing)</li></ul><h3 id="dual-quota-system" tabindex="-1">Dual Quota System <a class="header-anchor" href="#dual-quota-system" aria-label="Permalink to &quot;Dual Quota System&quot;">​</a></h3><p>The plugin simultaneously accesses <strong>two independent quota pools</strong>:</p><ol><li><strong>Antigravity quota</strong>: From Google Antigravity API</li><li><strong>Gemini CLI quota</strong>: From Google Gemini CLI</li></ol><p>When one pool is rate-limited, the plugin automatically tries the other pool, maximizing quota utilization.</p><h3 id="automatic-session-recovery" tabindex="-1">Automatic Session Recovery <a class="header-anchor" href="#automatic-session-recovery" aria-label="Permalink to &quot;Automatic Session Recovery&quot;">​</a></h3><ul><li>Detects tool call failures (such as interruptions by pressing ESC)</li><li>Automatically injects synthetic tool_result to prevent conversation crashes</li><li>Supports automatically sending &quot;continue&quot; to resume conversations</li></ul><h3 id="google-search-integration" tabindex="-1">Google Search Integration <a class="header-anchor" href="#google-search-integration" aria-label="Permalink to &quot;Google Search Integration&quot;">​</a></h3><p>Enables web search for Gemini models to improve factual accuracy:</p><ul><li><strong>Auto mode</strong>: The model decides whether to search based on need</li><li><strong>Always-on mode</strong>: Search is performed every time</li></ul><h2 id="when-to-use-this-plugin" tabindex="-1">When to Use This Plugin <a class="header-anchor" href="#when-to-use-this-plugin" aria-label="Permalink to &quot;When to Use This Plugin&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Ideal for These Scenarios</p><ul><li>You have multiple Google accounts and want to increase overall quota</li><li>You need to use Claude or Gemini 3&#39;s Thinking models</li><li>You want to enable Google Search for Gemini models</li><li>You prefer OAuth authentication over managing API keys manually</li><li>You frequently encounter rate limits and want automatic account switching</li></ul></div><div class="warning custom-block"><p class="custom-block-title">Not Suitable for These Scenarios</p><ul><li>You need to use models not officially announced by Google</li><li>You&#39;re highly sensitive to Google ToS risks (see risk warnings below)</li><li>You only need basic Gemini 1.5 or Claude 3 models (official APIs are more stable)</li><li>You have difficulty opening browsers in WSL, Docker, or similar environments</li></ul></div><h2 id="⚠️-important-risk-warnings" tabindex="-1">⚠️ Important Risk Warnings <a class="header-anchor" href="#⚠️-important-risk-warnings" aria-label="Permalink to &quot;⚠️ Important Risk Warnings&quot;">​</a></h2><p>Using this plugin <strong>may violate Google&#39;s Terms of Service</strong>. Some users have reported their Google accounts being <strong>banned</strong> or <strong>shadow-banned</strong> (restricted access without explicit notification).</p><h3 id="high-risk-scenarios" tabindex="-1">High-Risk Scenarios <a class="header-anchor" href="#high-risk-scenarios" aria-label="Permalink to &quot;High-Risk Scenarios&quot;">​</a></h3><ul><li>🚨 <strong>Brand new Google accounts</strong>: Extremely high probability of being banned</li><li>🚨 <strong>Accounts with newly activated Pro/Ultra subscriptions</strong>: Easily flagged and banned</li></ul><h3 id="confirm-before-use" tabindex="-1">Confirm Before Use <a class="header-anchor" href="#confirm-before-use" aria-label="Permalink to &quot;Confirm Before Use&quot;">​</a></h3><ul><li>This is an <strong>unofficial tool</strong>, not endorsed by Google</li><li>Your account may be suspended or permanently banned</li><li>You assume all risks associated with using this plugin</li></ul><h3 id="recommendations" tabindex="-1">Recommendations <a class="header-anchor" href="#recommendations" aria-label="Permalink to &quot;Recommendations&quot;">​</a></h3><ul><li>Use <strong>established Google accounts</strong>, not newly created accounts for this plugin</li><li>Avoid using important accounts linked to critical services</li><li>If your account is banned, you cannot appeal through this plugin</li></ul><div class="danger custom-block"><p class="custom-block-title">Account Security</p><p>All OAuth tokens are stored locally in <code>~/.config/opencode/antigravity-accounts.json</code> and are not uploaded to any server. However, please ensure your computer is secure to prevent token leakage.</p></div><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><p>Antigravity Auth is a powerful OpenCode plugin that lets you access advanced Claude and Gemini 3 models through Google OAuth. It provides features like multi-account load balancing, dual quota pools, and automatic session recovery, making it ideal for users who need advanced models and automated management.</p><p>But please note: <strong>Using this plugin carries the risk of account bans</strong>. Please use non-critical Google accounts and understand the related risks before proceeding with installation.</p><h2 id="coming-up-next" tabindex="-1">Coming Up Next <a class="header-anchor" href="#coming-up-next" aria-label="Permalink to &quot;Coming Up Next&quot;">​</a></h2><blockquote><p>In the next lesson, we&#39;ll learn <strong><a href="./../quick-install/">Quick Install</a></strong>.</p><p>You&#39;ll learn:</p><ul><li>Complete plugin installation in 5 minutes</li><li>Add your first Google account</li><li>Verify successful installation</li></ul></blockquote>',42)])])}const m=t(n,[["render",l]]);export{g as __pageData,m as default};
